output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?celebrity ?celebrityLabel WHERE {
  wd:Q85946144 wdt:P161 ?celebrity .
  ?celebrity wdt:P31 wd:Q5 .
  ?celebrity rdfs:label ?celebrityLabel .
  FILTER(LANG(?celebrityLabel) = 'en')
  FILTER NOT EXISTS {
    ?celebrity wdt:P106 wd:Q48595
  }
}

